$8d5c669e = ""
function Load-LemonHerb { param([Parameter ()] $xk = "")
$xk -eq "" -and ($xk = Read-Host "Specify XorKey")
$fb = [Convert]::FromBase64String($8d5c669e)
for($i=0; $i -lt $fb.count ; $i++) {$fb[$i] = $fb[$i] -bxor $xk}
[System.Reflection.Assembly]::Load($fb)
}
function Invoke-LemonHerb { param([Parameter ()] $Args = "")
$Args -eq "" -and ($Args = Read-Host "Specify command arguments")
try {[SharpShares.Program]::"Main"($Args.split())}
catch { try {$asm.GetType("SharpShares.Program", [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))}
catch {$asm.GetType([SharpShares.Program], [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))}}
}
